package com.example.datatransfer;

import io.grpc.ManagedChannel;
import io.grpc.ManagedChannelBuilder;
import io.grpc.stub.StreamObserver;

import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;
import java.util.UUID;
import java.util.concurrent.CountDownLatch;
import java.util.concurrent.TimeUnit;

public class DataTransferClient {
    private final ManagedChannel channel;
    private final DataTransferServiceGrpc.DataTransferServiceStub asyncStub;
    private final DataTransferServiceGrpc.DataTransferServiceBlockingStub blockingStub;

    public DataTransferClient(String host, int port) {
        this.channel = ManagedChannelBuilder.forAddress(host, port)
                .usePlaintext()
                .maxInboundMessageSize(Integer.MAX_VALUE)
                .build();
        this.asyncStub = DataTransferServiceGrpc.newStub(channel);
        this.blockingStub = DataTransferServiceGrpc.newBlockingStub(channel);
    }

    public UploadResponse uploadFile(Path file) throws Exception {
        CountDownLatch latch = new CountDownLatch(1);
        UploadResponse[] result = new UploadResponse[1];
        Throwable[] error = new Throwable[1];

        StreamObserver<UploadResponse> responseObserver = new StreamObserver<UploadResponse>() {
            @Override
            public void onNext(UploadResponse value) {
                result[0] = value;
            }

            @Override
            public void onError(Throwable t) {
                error[0] = t;
                latch.countDown();
            }

            @Override
            public void onCompleted() {
                latch.countDown();
            }
        };

        StreamObserver<UploadRequest> requestObserver = asyncStub.upload(responseObserver);

        requestObserver.onNext(UploadRequest.newBuilder()
                .setMetadata(UploadMetadata.newBuilder()
                        .setFileName(file.getFileName().toString())
                        .build())
                .build());

        byte[] bytes = Files.readAllBytes(file);
        int offset = 0;
        int chunkSize = 1024 * 1024;
        while (offset < bytes.length) {
            int len = Math.min(chunkSize, bytes.length - offset);
            requestObserver.onNext(UploadRequest.newBuilder()
                    .setChunk(com.google.protobuf.ByteString.copyFrom(bytes, offset, len))
                    .build());
            offset += len;
        }

        requestObserver.onCompleted();

        if (!latch.await(5, TimeUnit.MINUTES)) {
            throw new RuntimeException("Upload timed out");
        }
        if (error[0] != null) {
            throw new RuntimeException(error[0]);
        }
        return result[0];
    }

    public void downloadFile(String fileName, Path target) throws Exception {
        Files.deleteIfExists(target);
        Files.createDirectories(target.getParent() == null ? Paths.get(".") : target.getParent());

        try (var out = Files.newOutputStream(target)) {
            blockingStub.download(DownloadRequest.newBuilder().setFileName(fileName).build())
                    .forEachRemaining(chunk -> {
                        try {
                            chunk.getChunk().writeTo(out);
                        } catch (Exception e) {
                            throw new RuntimeException(e);
                        }
                    });
        }
    }

    public void bidirectionalTransfer() throws Exception {
        CountDownLatch latch = new CountDownLatch(1);

        StreamObserver<TransferMessage> responseObserver = new StreamObserver<TransferMessage>() {
            @Override
            public void onNext(TransferMessage value) {
                System.out.println("Received response: " + value.getCorrelationId() + " bytes=" + value.getPayload().size());
            }

            @Override
            public void onError(Throwable t) {
                latch.countDown();
            }

            @Override
            public void onCompleted() {
                latch.countDown();
            }
        };

        StreamObserver<TransferMessage> requestObserver = asyncStub.transfer(responseObserver);

        for (int i = 0; i < 5; i++) {
            requestObserver.onNext(TransferMessage.newBuilder()
                    .setCorrelationId(UUID.randomUUID().toString())
                    .setPayload(com.google.protobuf.ByteString.copyFromUtf8("message-" + i))
                    .putHeaders("type", "demo")
                    .build());
        }

        requestObserver.onCompleted();
        latch.await(1, TimeUnit.MINUTES);
    }

    public void shutdown() throws InterruptedException {
        channel.shutdown().awaitTermination(30, TimeUnit.SECONDS);
    }

    public static void main(String[] args) throws Exception {
        DataTransferClient client = new DataTransferClient("localhost", 50051);
        try {
            Path sample = Paths.get("sample.bin");
            if (!Files.exists(sample)) {
                Files.write(sample, new byte[2 * 1024 * 1024]);
            }
            UploadResponse response = client.uploadFile(sample);
            System.out.println("Uploaded: " + response.getUploadId() + " bytes=" + response.getTotalBytes());
            client.downloadFile(sample.getFileName().toString(), Paths.get("downloaded-" + sample.getFileName()));
            client.bidirectionalTransfer();
        } finally {
            client.shutdown();
        }
    }
}